import{_ as s,o as e,c as n,ag as t}from"./chunks/framework.BDReElpY.js";const h=JSON.parse('{"title":"Variables & Constants","description":"","frontmatter":{},"headers":[],"relativePath":"guide/basics/variables.md","filePath":"guide/basics/variables.md"}'),i={name:"guide/basics/variables.md"};function l(p,a,o,c,r,d){return e(),n("div",null,[...a[0]||(a[0]=[t(`<h1 id="variables-constants" tabindex="-1">Variables &amp; Constants <a class="header-anchor" href="#variables-constants" aria-label="Permalink to &quot;Variables &amp; Constants&quot;">​</a></h1><p>Vex provides three ways to declare bindings: <code>let</code> for immutable variables, <code>let!</code> for mutable variables, and <code>const</code> for compile-time constants.</p><h2 id="immutable-variables-let" tabindex="-1">Immutable Variables (<code>let</code>) <a class="header-anchor" href="#immutable-variables-let" aria-label="Permalink to &quot;Immutable Variables (\`let\`)&quot;">​</a></h2><p>By default, variables in Vex are <strong>immutable</strong>. Once assigned, their value cannot be changed:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let x = 42</span></span>
<span class="line"><span>let name = &quot;Vex&quot;</span></span>
<span class="line"><span>let pi = 3.14159</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// x = 100</span><span>  // ERROR: Cannot assign to immutable variable</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">Why Immutable by Default?</p><p>Immutable bindings make code easier to reason about, enable better optimizations, and prevent accidental mutations. This is a key principle in Vex&#39;s safety model.</p></div><h2 id="mutable-variables-let" tabindex="-1">Mutable Variables (<code>let!</code>) <a class="header-anchor" href="#mutable-variables-let" aria-label="Permalink to &quot;Mutable Variables (\`let!\`)&quot;">​</a></h2><p>When you need to modify a variable, use <code>let!</code>:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let! counter = 0</span></span>
<span class="line"><span>counter = counter + 1  // OK</span></span>
<span class="line"><span>counter += 1           // OK</span></span>
<span class="line"><span></span></span>
<span class="line"><span>let! buffer = Vec&lt;u8&gt;.new()</span></span>
<span class="line"><span>buffer.push(42)        // OK - mutation allowed</span></span></code></pre></div><p>The <code>!</code> suffix serves as a visual marker that this variable can change, making mutation explicit and intentional.</p><h2 id="constants-const" tabindex="-1">Constants (<code>const</code>) <a class="header-anchor" href="#constants-const" aria-label="Permalink to &quot;Constants (\`const\`)&quot;">​</a></h2><p>Constants are evaluated at <strong>compile time</strong> and must have an explicit type annotation:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>const MAX_SIZE: i32 = 1024</span></span>
<span class="line"><span>const PI: f64 = 3.14159265358979</span></span>
<span class="line"><span>const APP_NAME: string = &quot;MyApp&quot;</span></span>
<span class="line"><span>const BUFFER_SIZE: usize = 2048</span></span></code></pre></div><h3 id="const-vs-let" tabindex="-1">Const vs Let <a class="header-anchor" href="#const-vs-let" aria-label="Permalink to &quot;Const vs Let&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Feature</th><th><code>let</code></th><th><code>const</code></th></tr></thead><tbody><tr><td>Evaluation</td><td>Runtime</td><td>Compile-time</td></tr><tr><td>Type annotation</td><td>Optional</td><td>Required</td></tr><tr><td>Memory</td><td>Stack/Heap</td><td>Inlined</td></tr></tbody></table><h2 id="type-annotations" tabindex="-1">Type Annotations <a class="header-anchor" href="#type-annotations" aria-label="Permalink to &quot;Type Annotations&quot;">​</a></h2><p>Type annotations are optional when the type can be inferred:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// Inferred types</span></span>
<span class="line"><span>let x = 42          // i32 (default integer type)</span></span>
<span class="line"><span>let y = 3.14        // f64 (default float type)</span></span>
<span class="line"><span>let z = true        // bool</span></span>
<span class="line"><span>let s = &quot;hello&quot;     // string</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Explicit types</span></span>
<span class="line"><span>let a: i64 = 42</span></span>
<span class="line"><span>let b: f32 = 3.14</span></span>
<span class="line"><span>let c: u8 = 255</span></span></code></pre></div><h2 id="shadowing" tabindex="-1">Shadowing <a class="header-anchor" href="#shadowing" aria-label="Permalink to &quot;Shadowing&quot;">​</a></h2><p>You can redeclare a variable with the same name, which <strong>shadows</strong> the previous binding:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let x = 5</span></span>
<span class="line"><span>let x = x * 2      // x is now 10</span></span>
<span class="line"><span>let x = &quot;hello&quot;    // x is now a string (type can change)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>fn example() {</span></span>
<span class="line"><span>    let value = 10</span></span>
<span class="line"><span>    {</span></span>
<span class="line"><span>        let value = 20  // Shadows outer \`value\`</span></span>
<span class="line"><span>        println(value)  // Prints: 20</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>    println(value)      // Prints: 10 (original)</span></span>
<span class="line"><span>}</span></span></code></pre></div><h2 id="destructuring" tabindex="-1">Destructuring <a class="header-anchor" href="#destructuring" aria-label="Permalink to &quot;Destructuring&quot;">​</a></h2><p>Variables can be declared using pattern destructuring:</p><h3 id="tuple-destructuring" tabindex="-1">Tuple Destructuring <a class="header-anchor" href="#tuple-destructuring" aria-label="Permalink to &quot;Tuple Destructuring&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let (x, y) = (10, 20)</span></span>
<span class="line"><span>let (first, _, third) = (1, 2, 3)  // _ ignores a value</span></span></code></pre></div><h3 id="struct-destructuring" tabindex="-1">Struct Destructuring <a class="header-anchor" href="#struct-destructuring" aria-label="Permalink to &quot;Struct Destructuring&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>struct Point { x: f64, y: f64 }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>let point = Point { x: 3.0, y: 4.0 }</span></span>
<span class="line"><span>let Point { x, y } = point</span></span></code></pre></div><h2 id="late-initialization" tabindex="-1">Late Initialization <a class="header-anchor" href="#late-initialization" aria-label="Permalink to &quot;Late Initialization&quot;">​</a></h2><p>Variables can be declared without initialization and assigned later:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let x: i32           // Declared but not initialized</span></span>
<span class="line"><span>// println(x)</span><span>        // ERROR: Use of uninitialized variable</span></span>
<span class="line"><span></span></span>
<span class="line"><span>x = 10               // Now initialized</span></span>
<span class="line"><span>println(x)           // OK</span></span></code></pre></div><p>The borrow checker ensures you never use an uninitialized variable.</p><h2 id="best-practices" tabindex="-1">Best Practices <a class="header-anchor" href="#best-practices" aria-label="Permalink to &quot;Best Practices&quot;">​</a></h2><ol><li><strong>Prefer <code>let</code> over <code>let!</code></strong>: Only use mutation when necessary.</li><li><strong>Use meaningful names</strong>: <code>user_count</code> instead of <code>n</code>.</li><li><strong>Scope variables tightly</strong>: Declare variables close to their first use.</li><li><strong>Use <code>const</code> for configuration</strong>: Makes intent and compile-time nature clear.</li></ol><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="/docs/guide/types/primitives">Primitive Types</a> - All built-in types</li><li><a href="/docs/guide/basics/functions">Functions</a> - Working with functions</li><li><a href="/docs/guide/memory/ownership">Ownership</a> - How variables own data</li></ul>`,35)])])}const b=s(i,[["render",l]]);export{h as __pageData,b as default};
